/**
 * secretHandler throughput / backtracking detection benchmarks.
 *
 * Purpose
 * -------
 * Catch catastrophic regex backtracking in the secret-scanning hook before
 * it ships. A naive regex change (e.g., adding `.*` next to a `\b` boundary)
 * can turn a microsecond-scale scan into a multi-second one for adversarial
 * inputs. We don't trust wall-clock numbers in functional tests because the
 * test runner runs under v8 coverage instrumentation, parallel workers, and
 * thermal jitter — see the design note in `README.md` next to this file.
 *
 * How to run
 * ----------
 *   npm run bench                 # full bench suite
 *   npm run bench -- secret       # filter to this file
 *
 * How to read the report
 * ----------------------
 * Vitest prints a Tinybench table per scenario:
 *
 *   name | hz | min | max | mean | p75 | p99 | p995 | p999 | rme | samples
 *
 *   - Watch p99, not max. Catastrophic backtracking inflates *many* samples;
 *     `max` is dominated by single-event noise (GC pause, scheduler swap).
 *   - `rme` (relative margin of error) should sit under 3%. If higher,
 *     increase `time` or `iterations` and re-run.
 *
 * What to do on regression
 * ------------------------
 *   1. Compare the p99 against the baseline numbers in this file's header
 *      comments. A >2x slowdown on the secret-bearing scenarios with no
 *      change to `secret-redactor.ts` regex is a smoking gun for backtracking.
 *   2. Profile with `--cpu-prof` or paste the regex into regex101.com with
 *      input from the bench's filler/secret pair to see backtracking steps.
 *   3. If you intentionally added scanning, raise the baseline here AND
 *      verify p99 didn't shift on `no-secret 50KB` (the regex sweep
 *      shouldn't pay extra cost just for showing up).
 *
 * Baseline (Apple M-series, Node 22, no instrumentation, measured 2026-05-12):
 *   5KB   - PAT embedded            p99 ~0.077 ms  rme <1%
 *   50KB  - PAT embedded            p99 ~0.194 ms  rme ~8%  (raise time= if higher)
 *   500KB - PAT embedded            p99 ~1.156 ms  rme <1%
 *   50KB  - no secret (canary)      p99 ~0.136 ms  rme <1%
 *
 * Useful ratios derived from the baseline:
 *   - 50KB w/ pat vs 50KB no secret: ~1.43x (redaction overhead)
 *   - 50KB w/ pat vs 500KB w/ pat:   ~6x (sublinear-ish in payload size)
 *
 * Numbers will be 2-4x slower in coverage mode and on slower CI runners.
 * Use the *ratio* between scenarios as the portable regression signal —
 * it cancels CPU-frequency differences. A 10x+ shift in the no-secret
 * canary with no regex change is the strongest backtracking signal.
 */

import { bench, describe, beforeAll } from 'vitest';
import { secretHandler } from '../posttool/secret-handler.js';
import { NOOP_CTX } from '../lib/context.js';
import type { HookInput } from '../types.js';

// Reuse the production NOOP context — bench code must not depend on
// test-only fixtures and must use the same shape as real hook invocations.
const ctx = NOOP_CTX;

function makeInput(toolOutput: string): HookInput {
  return {
    tool_name: 'Read',
    session_id: 'bench-session',
    tool_input: { file_path: '/tmp/x.txt' },
    tool_output: toolOutput,
  };
}

// Construct the fake PAT fixture from parts so the secret-scanner hook
// doesn't flag this source file itself. Matches the existing test fixture
// pattern in `src/__tests__/posttool/secret-handler.test.ts`.
const SECRET = ['gh', 'p_', 'aBcDeFgHiJkLmNoPqRsTuVwXyZ0123456789AB'].join('');

function buildPayload(size: number, withSecret: boolean): string {
  // The trailing/leading space ensures \b matches around the embedded secret.
  if (!withSecret) return 'A'.repeat(size);
  const half = Math.floor((size - SECRET.length) / 2);
  return `${'A'.repeat(half)} ${SECRET} ${'B'.repeat(size - half - SECRET.length - 2)}`;
}

const PAYLOAD_5KB_SECRET    = buildPayload(5_000,   true);
const PAYLOAD_50KB_SECRET   = buildPayload(50_000,  true);
const PAYLOAD_50KB_NONE     = buildPayload(50_000,  false);
const PAYLOAD_500KB_SECRET  = buildPayload(500_000, true);

beforeAll(() => {
  process.env.ORK_SECRET_HOOK = 'REDACT';
});

// `time` is total sample-collection window (ms). Warmup gives JIT a chance
// to inline + shape hot paths so the first few samples aren't outliers.
const OPTS = { time: 1000, warmupTime: 500, warmupIterations: 10 } as const;

describe('secretHandler - payload size scaling', () => {
  bench('5KB - PAT embedded', () => {
    secretHandler(makeInput(PAYLOAD_5KB_SECRET), ctx);
  }, OPTS);

  bench('50KB - PAT embedded', () => {
    secretHandler(makeInput(PAYLOAD_50KB_SECRET), ctx);
  }, OPTS);

  bench('500KB - PAT embedded', () => {
    secretHandler(makeInput(PAYLOAD_500KB_SECRET), ctx);
  }, { ...OPTS, time: 2000 });
});

describe('secretHandler - backtracking guard (no-secret baseline)', () => {
  // The no-secret case is the regression canary: if the scanning regex
  // suddenly takes 10x longer here, the change is paying cost for inputs
  // that have nothing to redact — a classic backtracking smell.
  bench('50KB - no secret (regex sweep only)', () => {
    secretHandler(makeInput(PAYLOAD_50KB_NONE), ctx);
  }, OPTS);
});
